window.ASBAB_NUZUL_CACHE["25"] = {"asbab_nuzul":{"27":[{"ar":"عن ابن عباس رضي الله عنها: أن أبا معيط - هو عقبة بن أبي معيط -كان يجلس مع النبي ﷺ بمكة لا يؤذيه، وكان رجلاً حليماً، وكان بقية قريش إذا جلسوا معه آذوه، وكان لأبي معيط خليل غائب عنه بالشام، فقالت قريش صبأ أبو معيط، وقدم خليله من الشام ليلاً، فقال لامرأته: ما فعل محمد مما كان عليه؟ فقالت: أشد مما كان أمراً. فقال: ما فعل خليلي أبو معيط؟ فقالت: صبأ. فبات بليلة سوء، فلما أصبح أتاه أبو معيط فحياه، فلم يرد عليه التحية، فقال: ما لك لا ترد على تحيتي؟\n\nفقال: كيف أرد عليك تحيتك وقد صبوت؟ قال: أو قد فعلتها قريش؟ قال: نعم. قال: فما يبرئ صدورهم إن أنا فعلت؟ قال: تأتيه في مجلسه وتبصق في وجهه، وتشتمه بأخبث ما تعلمه من الشتم، ففعل، فلم يزد النبي ﷺ أن مسح وجهه من البصاق، ثم التفت إليه فقال: « إن وجدتك خارجاً من جبال مكة، أضرب عنقك صبراً ».\n\nفلما كان يوم بدر، وخرج أصحابه أبى أن يخرج، فقال له أصحابه: اخرج معنا، قال: قد وعدني هذا الرجل إن وجدني خارجاً من جبال مكة أن يضرب عنقي صبراً.\n\nفقالوا: لك جمل أحمر لا يدرك، فلو كانت الهزيمة طرت عليه. فخرج معهم، فلما هزم الله المشركين، وحل به جمله في جدد من الأرض، فأخذه رسول الله ﷺ أسيراً في سبعين من قريش، وقدم إليه أبو معيط فقال: تقتلني من بين هؤلاء؟ قال: « نعم، بما بصقت في وجهي » فأنزل الله في أبي معيط الآية.","id":""}],"32":[{"ar":"عن ابن عباس رضي الله عنهما قال: قال المشركون: لو كان محمد كما يزعم نبياً فلم يعذبه ربه؟ ألا ينزل عليه القرآن جملة واحدة؟ ينزل عليه الآية والآيتين، والسورة والسورتين فأنزل الله على نبيه جواب ما قالوا: { وَقَالَ ٱلَّذِينَ كَفَرُوا۟ لَوْلَا نُزِّلَ عَلَيْهِ ٱلْقُرْءَانُ جُمْلَةً وَٰحِدَةً ۚ كَذَٰلِكَ لِنُثَبِّتَ بِهِۦ فُؤَادَكَ ۖ وَرَتَّلْنَـٰهُ تَرْتِيلًا ﴿٣٢﴾ }.","id":""}],"68":[{"ar":"عن ابن عباس رضي الله عنهما قال: أن ناساً من أهل الشرك قتلوا فأكثروا، وزنوا فأكثروا، ثم أتوا محمداً ﷺ، فقالوا: إن الذي تقول وتدعو لحسن، ولو تخبرنا أن لما عملنا كفارة، فنزل: { وَٱلَّذِينَ لَا يَدْعُونَ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ وَلَا يَقْتُلُونَ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ وَلَا يَزْنُونَ ۚ وَمَن يَفْعَلْ ذَٰلِكَ يَلْقَ أَثَامًا ﴿٦٨﴾ } [الفرقان: ٦٨] { قُلْ يَـٰعِبَادِىَ ٱلَّذِينَ أَسْرَفُوا۟ عَلَىٰٓ أَنفُسِهِمْ لَا تَقْنَطُوا۟ مِن رَّحْمَةِ ٱللَّهِ ۚ إِنَّ ٱللَّهَ يَغْفِرُ ٱلذُّنُوبَ جَمِيعًا ۚ إِنَّهُۥ هُوَ ٱلْغَفُورُ ٱلرَّحِيمُ ﴿٥٣﴾ } [الزمر: ٥٣].","id":""},{"ar":"وهناك سبب ثان لنزول الآية: فقد جاء عن عمرو بن شرحبيل قال: قال عبد الله رضي الله عنه: قال رجل: يا رسول الله أي الذنب أكبر عند الله؟ قال: « أن تدعو الله نداً وهو خلقك » قَالَ: ثُمَّ أَيُّ؟ قَالَ: « أَنْ تَقْتُل وَلَدَكَ مَخَافَةَ أَنْ يَطْعَمَ مَعَكَ »، قَالَ: ثُمَّ أَيُّ؟ قَالَ: « أَنْ تُزَانِي حَلِيلَةَ جَارِكَ »، فَأَنْزَلَ اللهُ عز و جل تَصْدِيقَهَا: { وَٱلَّذِينَ لَا يَدْعُونَ مَعَ ٱللَّهِ إِلَٰهًا ءَاخَرَ وَلَا يَقْتُلُونَ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ وَلَا يَزْنُونَ ۚ وَمَن يَفْعَلْ ذَٰلِكَ يَلْقَ أَثَامًا ﴿٦٨﴾ }.","id":""}],"70":[{"ar":"عَنْ سَعِيدِ بْنِ جُبَيْرٍ رحمه الله قَالَ: أَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ: سَلِ ابْنَ عَبَّاسِ رضي الله عنهما عَنْ هَاتَيْنِ الْآيَتَيْنِ، مَا أَمْرُهُمَا؟: { وَلَا تَقْتُلُوا۟ ٱلنَّفْسَ ٱلَّتِى حَرَّمَ ٱللَّهُ إِلَّا بِٱلْحَقِّ ۚ } [الأنعام: ١٥١] { وَمَن يَقْتُلْ مُؤْمِنًا مُّتَعَمِّدًا } [النساء: ٩٣].\n\nفَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ: لَمَّا أُنْزِلَتِ الَّتِي فِي الْفُرْقَانِ، قَالَ مُشْرِكُوا أَهْلِ مَكَّةَ: فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللهُ، وَدَعَوْنَا مَعَ اللهِ إِلَهَاً آخَرَ، وَقَدْ أَتَيْنَا الْفَوَاحِشَ، فَأَنْزَلَ اللهُ: { إِلَّا مَن تَابَ وَءَامَنَ } الآية.","id":""}]},"mapping_ayat":{"25:33":[{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."}],"25:53":[{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Muslim","n":173,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمِ بْنِ مَيْمُونٍ وَإِبْرَاهِيمُ بْنُ دِينَارٍ وَاللَّفْظُ لِإِبْرَاهِيمَ قَالَا حَدَّثَنَا حَجَّاجٌ وَهُوَ ابْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي يَعْلَى بْنُ مُسْلِمٍ أَنَّهُ سَمِعَ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍأَنَّ نَاسًا مِنْ أَهْلِ الشِّرْكِ قَتَلُوا فَأَكْثَرُوا وَزَنَوْا فَأَكْثَرُوا ثُمَّ أَتَوْا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّ الَّذِي تَقُولُ وَتَدْعُو لَحَسَنٌ وَلَوْ تُخْبِرُنَا أَنَّ لِمَا عَمِلْنَا كَفَّارَةً فَنَزَلَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا }وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Maimun] dan [Ibrahim bin Dinar] dan lafazh tersebut milik Ibrahim, keduanya berkata, telah menceritakan kepada kami [Hajjaj] -yaitu Ibnu Muhammad- dari [Ibnu Juraij] dia berkata, telah mengabarkan kepadaku [Ya'la bin Muslim] bahwa dia mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] bahwa orang-orang dari kaum musyrikin melakukan pembunuhan, dan hal itu semakin merajalela, dan mereka melakukan perzinahan, dan hal itupun semakin merajalela. Kemudian mereka mendatangi Nabi Muhammad shallallahu 'alaihi wasallam dan berkata, 'Sungguh sesuatu yang selalu engkau katakan dan engkau serukan adalah baik adanya, sekiranya engkau mengabarkan kepada kami bahwa amalan-amalan jelek yang telah kami perbuat dapat terhapus, maka turunlah ayat: '(Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar, dan tidak berzina, barang siapa yang melakukan yang demikian itu, niscaya dia mendapat (pembalasan) dosa(nya)) ' (Qs. Al Furqan: 68). Lalu turunlah ayat: '(Katakanlah, 'Hai hamba-hambaKu yang malampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah) ' (Qs. Az Zumar: 53)."}],"25:68":[{"p":"Abu Dawud","n":3609,"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ مُجَالِدِ بْنِ عَوْفٍ أَنَّ خَارِجَةَ بْنَ زَيْدٍ قَالَ سَمِعْتُ زَيْدَ بْنَ ثَابِتٍفِي هَذَا الْمَكَانِ يَقُولُ أُنْزِلَتْ هَذِهِ الْآيَةُ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ خَالِدًا فِيهَا }بَعْدَ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }بِسِتَّةِ أَشْهُرٍ","trj":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami ['Abdurrahman bin Ishaq] dari [Abu Az Zinad] dari [Mujalid bin Auf] bahwa [Kharijah bin Zaid] berkata; Aku mendengar [Zaid bin Tsabit] berkata di tempat ini, \"Firman Allah ini: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam, ia kekal di dalamnya..) -An Nisa: 93-, diturunkan setelah ayat Allah yang ada dalam surat Al Furqan: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68- jaraknya adalah enam bulam.\""},{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Bukhari","n":6608,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ قَالَ قَالَ عَبْدُ اللَّهِقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَكْبَرُ عِنْدَ اللَّهِ قَالَ أَنْ تَدْعُوَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قَالَ ثُمَّ أَيْ قَالَ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ أَنْ يَطْعَمَ مَعَكَ قَالَ ثُمَّ أَيْ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ فَأَنْزَلَ اللَّهُ تَصْدِيقَهَا{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا يُضَاعَفْ لَهُ الْعَذَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wail] dari ['Amru bin Syurahbil] berkata, [Abdullah] berkata, \"Seorang laki-laki berkata, 'Wahai Rasulullah, dosa apakah yang terbesar di sisi Allah? ' Nabi menjawab: 'Engkau menjadikan tandingan bagi Allah, padahal Dialah yang menciptamu.' Laki-laki tersebut bertanya lagi, 'Lantas apa lagi? ' Nabi menjawab: 'Engkau bunuh anakmu karena khawatir makan bersamamu.' Laki-laki itu bertanya lagi, 'Lantas apa? ' Nabi menjawab: 'Engkau berzina dengan wanita tetanggamu.' Lantas Allah menurunkan ayat yang membenarkannya: '(Dan orang-orang yang tidak menyeru Tuhan lain disamping menyeru Allah, dan tidak membunuh jiwa yang Allah haramkan selain dengan alasan yang benar, dan tidak berzina, dan barangsiapa melakukan yang demikian ia akan memperoleh dosa dan akan dilipat gandakan siksa baginya) '. (Qs. Al Furqan: 68-69)."},{"p":"Muslim","n":173,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمِ بْنِ مَيْمُونٍ وَإِبْرَاهِيمُ بْنُ دِينَارٍ وَاللَّفْظُ لِإِبْرَاهِيمَ قَالَا حَدَّثَنَا حَجَّاجٌ وَهُوَ ابْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي يَعْلَى بْنُ مُسْلِمٍ أَنَّهُ سَمِعَ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍأَنَّ نَاسًا مِنْ أَهْلِ الشِّرْكِ قَتَلُوا فَأَكْثَرُوا وَزَنَوْا فَأَكْثَرُوا ثُمَّ أَتَوْا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّ الَّذِي تَقُولُ وَتَدْعُو لَحَسَنٌ وَلَوْ تُخْبِرُنَا أَنَّ لِمَا عَمِلْنَا كَفَّارَةً فَنَزَلَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا }وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Maimun] dan [Ibrahim bin Dinar] dan lafazh tersebut milik Ibrahim, keduanya berkata, telah menceritakan kepada kami [Hajjaj] -yaitu Ibnu Muhammad- dari [Ibnu Juraij] dia berkata, telah mengabarkan kepadaku [Ya'la bin Muslim] bahwa dia mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] bahwa orang-orang dari kaum musyrikin melakukan pembunuhan, dan hal itu semakin merajalela, dan mereka melakukan perzinahan, dan hal itupun semakin merajalela. Kemudian mereka mendatangi Nabi Muhammad shallallahu 'alaihi wasallam dan berkata, 'Sungguh sesuatu yang selalu engkau katakan dan engkau serukan adalah baik adanya, sekiranya engkau mengabarkan kepada kami bahwa amalan-amalan jelek yang telah kami perbuat dapat terhapus, maka turunlah ayat: '(Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar, dan tidak berzina, barang siapa yang melakukan yang demikian itu, niscaya dia mendapat (pembalasan) dosa(nya)) ' (Qs. Al Furqan: 68). Lalu turunlah ayat: '(Katakanlah, 'Hai hamba-hambaKu yang malampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah) ' (Qs. Az Zumar: 53)."}],"25:69":[{"p":"Bukhari","n":6608,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ قَالَ قَالَ عَبْدُ اللَّهِقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَكْبَرُ عِنْدَ اللَّهِ قَالَ أَنْ تَدْعُوَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قَالَ ثُمَّ أَيْ قَالَ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ أَنْ يَطْعَمَ مَعَكَ قَالَ ثُمَّ أَيْ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ فَأَنْزَلَ اللَّهُ تَصْدِيقَهَا{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا يُضَاعَفْ لَهُ الْعَذَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wail] dari ['Amru bin Syurahbil] berkata, [Abdullah] berkata, \"Seorang laki-laki berkata, 'Wahai Rasulullah, dosa apakah yang terbesar di sisi Allah? ' Nabi menjawab: 'Engkau menjadikan tandingan bagi Allah, padahal Dialah yang menciptamu.' Laki-laki tersebut bertanya lagi, 'Lantas apa lagi? ' Nabi menjawab: 'Engkau bunuh anakmu karena khawatir makan bersamamu.' Laki-laki itu bertanya lagi, 'Lantas apa? ' Nabi menjawab: 'Engkau berzina dengan wanita tetanggamu.' Lantas Allah menurunkan ayat yang membenarkannya: '(Dan orang-orang yang tidak menyeru Tuhan lain disamping menyeru Allah, dan tidak membunuh jiwa yang Allah haramkan selain dengan alasan yang benar, dan tidak berzina, dan barangsiapa melakukan yang demikian ia akan memperoleh dosa dan akan dilipat gandakan siksa baginya) '. (Qs. Al Furqan: 68-69)."}],"25:70":[{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."}]},"mapping_surah":[{"p":"Abu Dawud","n":1232,"ar":"حَدَّثَنَا الْقَعْنَبِيُّ عَنْ مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدِ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا فَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ لَهُ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ فَقَرَأَ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِيَ اقْرَأْ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُحَدَّثَنَا مُحَمَّدُ بْنُ يَحْيَى بْنِ فَارِسٍ حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ قَالَ قَالَ الزُّهْرِيُّ إِنَّمَا هَذِهِ الْأَحْرُفُ فِي الْأَمْرِ الْوَاحِدِ لَيْسَ تَخْتَلِفُ فِي حَلَالٍ وَلَا حَرَامٍ","trj":"Telah menceritakan kepada Kami [Al Qa'nabi] dari [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari [Abdurrahman bin Abdul Qari], ia berkata; saya mendengar [Umar bin Al Khathab] berkata; aku mendengar Hisyam bin Hakim bin Hizam membaca Surat Al Furqan tidak seperti yang aku baca, dan Rasulullah telah membacakannya kepadaku, maka hampir aku tergesa-gesa untuk bertindak terhadapnya, kemudian aku mengurungkannya hingga ia pergi. Kemudian aku menarik selendangnya dan membawanya kepada Rasulullah shallallahu 'alaihi wasallam. Aku katakan; wahai Rasul, sesungguhnya aku telah mendengar orang ini membaca Surat Al Furqan tidak seperti yang telah engkau bacakan kepadaku. Kemudian Rasulullah shallallahu 'alaihi wasallam berkata kepadanya: \"Bacalah, kemudian ia membaca bacaan yang telah aku dengar. kemudian Rasulullah shallAllahu wa'alaihi wa sallam bersabda: \"Demikianlah Surat tersebut diturunkan.\" Kemudian beliau berkata kepadaku: \"Bacalah.\" Lalu aku membacanya. Kemudian beliau berkata: \"Demikianlah surat tersebut diturunkan.\" Kemudian beliau bersabda: \"Sesungguhnya Al Qur'an ini diturunkan dengan tujuh gaya bahasa, maka bacalah apa yang mudah darinya.\" Telah menceritakan kepada Kami Muhammad bin Yahya bin Faris, telah menceritakan kepada Kami Abdurrazzaq, telah mengabarkan kepada Kami Ma'mar, ia berkata; Az Zuhri berkata; sesungguhnya gaya bahasa ini dalam satu perkara dan tidak berbeda-beda dalam hal halal dan haram. "},{"p":"Abu Dawud","n":3609,"ar":"حَدَّثَنَا مُسْلِمُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَمَّادٌ أَخْبَرَنَا عَبْدُ الرَّحْمَنِ بْنُ إِسْحَقَ عَنْ أَبِي الزِّنَادِ عَنْ مُجَالِدِ بْنِ عَوْفٍ أَنَّ خَارِجَةَ بْنَ زَيْدٍ قَالَ سَمِعْتُ زَيْدَ بْنَ ثَابِتٍفِي هَذَا الْمَكَانِ يَقُولُ أُنْزِلَتْ هَذِهِ الْآيَةُ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ خَالِدًا فِيهَا }بَعْدَ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }بِسِتَّةِ أَشْهُرٍ","trj":"Telah menceritakan kepada kami [Muslim bin Ibrahim] berkata, telah menceritakan kepada kami [Hammad] berkata, telah mengabarkan kepada kami ['Abdurrahman bin Ishaq] dari [Abu Az Zinad] dari [Mujalid bin Auf] bahwa [Kharijah bin Zaid] berkata; Aku mendengar [Zaid bin Tsabit] berkata di tempat ini, \"Firman Allah ini: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam, ia kekal di dalamnya..) -An Nisa: 93-, diturunkan setelah ayat Allah yang ada dalam surat Al Furqan: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68- jaraknya adalah enam bulam.\""},{"p":"Abu Dawud","n":3610,"ar":"حَدَّثَنَا يُوسُفُ بْنُ مُوسَى حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ عَنْ سَعِيدِ بْنِ جُبَيْرٍ أَوْ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَ سَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَلَمَّا نَزَلَتْ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ مُشْرِكُو أَهْلِ مَكَّةَ قَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَأَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ وَعَمِلَ عَمَلًا صَالِحًا فَأُولَئِكَ يُبَدِّلُ اللَّهُ سَيِّئَاتِهِمْ حَسَنَاتٍ }فَهَذِهِ لِأُولَئِكَ قَالَ وَأَمَّا الَّتِي فِي النِّسَاءِ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }الْآيَةَ قَالَ الرَّجُلُ إِذَا عَرَفَ شَرَائِعَ الْإِسْلَامِ ثُمَّ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ لَا تَوْبَةَ لَهُفَذَكَرْتُ هَذَا لِمُجَاهِدٍ فَقَالَ إِلَّا مَنْ نَدِمَ حَدَّثَنَا أَحْمَدُ بْنُ إِبْرَاهِيمَ حَدَّثَنَا حَجَّاجٌ عَنْ ابْنِ جُرَيْجٍ حَدَّثَنِي يَعْلَى عَنْ سَعِيدِ بْنِ جُبَيْرٍ عَنْ ابْنِ عَبَّاسٍ فِي هَذِهِ الْقِصَّةِ فِي{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }أَهْلِ الشِّرْكِ قَالَ وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Yusuf bin Musa] berkata, telah menceritakan kepada kami [Jarir] dari [Manshur] dari [Sa'id bin Jubair] atau ia mengatakan; telah menceritakan kepadaku [Al hakam] dari [Sa'id bin Jubair] ia berkata; Aku bertanya [Ibnu Abbas] berkata, \"Ketika ayat dalam surat Al furqan ini turun: (Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar..) -Al Furqan: 68-, orang-orang musyrik Makkah berkata, \"Kami telah membunuh jiwa yang telah diharamkan oleh Allah dan berbuat syirik kepada-Nya serta melakukan perbuatan keji!\" Allah pun menurunkan ayat: (Kecuali orang-orang yang bertaubat dan, beriman dan beramal shalih; maka kejahatan mereka akan diganti Allah dengan kebajikan..) -Qs. Al Furqan: 70-, maka ayat ini untuk orang-orang musyrik Quraisy tersebut. Ibnu Abbas melanjutkan, \"Sedangkan ayat yang ada dalam surat An Nisa: (Dan barangsiapa yang membunuh seorang mu'min dengan sengaja maka balasannya ialah Jahannam…) -An Nisa: 93- ia mengatakan, \"Seorang laki-laki yang mengetahui hukum-hukum Islam, kemudian ia membunuh seorang mukmin dengan sengaja, maka balasannya adalah neraka jahannam dan tidak ada lagi taubat untuknya.\" Perkataan ini lalu aku sebutkan kepada Mujahid, ia berkomentar, \"Kecuali jika ia (pembunuh) merasa menyesal.\" Telah menceritakan kepada kami [Ahmad bin Ibrahim] berkata, telah menceritakan kepada kami [Hajjaj] dari [Ibnu Juraij] berkata, telah menceritakan kepadaku [Ya'la] dari [Sa'id bin Jubair] dari [Ibnu Abbas] -sebagaimana kisah dalam hadits tersebut- tentang firman Allah: (dan orang-orang yang tidak menyembah tuhan yang lain berserta Allah..) -Qs. Al Furqan: 53- yakni orang-orang musyrik. Ibnu Abbas berkata, \"Lalu turun ayat: (Katakanlah, 'Hai hamba-hamba-Ku yang melampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah') -Qs. Az Zumar: 53-. "},{"p":"Bukhari","n":2241,"ar":"حَدَّثَنَا عَبْدُ اللَّهِ بْنُ يُوسُفَ أَخْبَرَنَا مَالِكٌ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّهُ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ رَضِيَ اللَّهُ عَنْهُ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا وَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ لِي أَرْسِلْهُ ثُمَّ قَالَ لَهُ اقْرَأْ فَقَرَأَ قَالَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِي اقْرَأْ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ إِنَّ الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مِنْهُ مَا تَيَسَّرَ","trj":"Telah menceritakan kepada kami ['Abdullah bin Yusuf] telah mengabarkan kepada kami [Malik] dari [Ibnu Syihab] dari ['Urwah bin Az Zubair] dari ['Abdurrahman bin 'Abdul Qariy] bahwa dia berkata, aku mendengar ['Umar bin Al Khaththob radliallahu 'anhu] berkata, aku mendengar Hisyam bin Hakim bin Hizam membaca surah Al Furqan dengan cara yang berbeda dari yang aku baca sebagaimana Rasulullah shallallahu 'alaihi wasallam membacakannya kepadaku dan hampir saja aku mau bertindak terhadapnya namun aku biarkan sejenak hingga dia selesai membaca. Setelah itu aku ikat dia dengan kainku lalu aku giring dia menghadap Rasulullah shallallahu 'alaihi wasallam dan aku katakan: \"Aku mendengar dia membaca Al Qur'an tidak sama dengan aku sebagaimana anda membacakannya kepadaku\". Maka Beliau berkata, kepadaku: \"Bawalah dia kemari\". Kemudian Beliau berkata, kepadanya: \"Bacalah\". Maka dia membaca. Beliau shallallahu 'alaihi wasallam kemudian bersabda: \"Begitulah memang yang diturunkan\". Kemudian Beliau berkata kepadaku: \"Bacalah\". Maka aku membaca. Beliau shallallahu 'alaihi wasallam bersabda: \"Begitulah memang yang diturunkan. Sesungguhnya Al Qur'an diturunkan dengan tujuh huruf, maka bacalah oleh kalian mana yang mudah\". "},{"p":"Bukhari","n":3409,"ar":"حَدَّثَنَا عُثْمَانُ بْنُ أَبِي شَيْبَةَ حَدَّثَنَا جَرِيرٌ عَنْ مَنْصُورٍ حَدَّثَنِي سَعِيدُ بْنُ جُبَيْرٍ أَوْ قَالَ حَدَّثَنِي الْحَكَمُ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَأَمَرَنِي عَبْدُ الرَّحْمَنِ بْنُ أَبْزَى قَالَ سَلْ ابْنَ عَبَّاسٍ عَنْ هَاتَيْنِ الْآيَتَيْنِ مَا أَمْرُهُمَا{ وَلَا تَقْتُلُوا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا }فَسَأَلْتُ ابْنَ عَبَّاسٍ فَقَالَ لَمَّا أُنْزِلَتْ الَّتِي فِي الْفُرْقَانِ قَالَ مُشْرِكُو أَهْلِ مَكَّةَ فَقَدْ قَتَلْنَا النَّفْسَ الَّتِي حَرَّمَ اللَّهُ وَدَعَوْنَا مَعَ اللَّهِ إِلَهًا آخَرَ وَقَدْ أَتَيْنَا الْفَوَاحِشَ فَأَنْزَلَ اللَّهُ{ إِلَّا مَنْ تَابَ وَآمَنَ }الْآيَةَ فَهَذِهِ لِأُولَئِكَ وَأَمَّا الَّتِي فِي النِّسَاءِ الرَّجُلُ إِذَا عَرَفَ الْإِسْلَامَ وَشَرَائِعَهُ ثُمَّ قَتَلَ فَجَزَاؤُهُ جَهَنَّمُفَذَكَرْتُهُ لِمُجَاهِدٍ فَقَالَإِلَّا مَنْ نَدِمَ","trj":"Telah menceritakan kepada kami ['Utsman bin Abu Syaibah] telah menceritakan kepada kami [Jarir] dari [Manshur] telah menceritakan kepadaku [Sa'id bin Jubair] -atau dia berkata, telah menceritakan kepadaku [Al Hakam] dari [Sa'id bin Jubair] berkata, - 'Abdurrahman bin Abza menyuruhku, katanya; \"Tanyalah kepada Ibnu 'Abbas tentang dua ayat ini dan apa maksudnya, yaitu yang pertama firman Allah dalam QS al Isra` ayat 33; (\"Dan janganlah kalian membunuh jiwa yang diharamkan Allah kecuali dengan haq (alasan yang benar) \" dan yang kedua firman Allah dalam QS an Nisaa' ayat 93: (\"Dan barangsiapa yang membunuh orang beriman dengan sengaja...\"). Maka aku bertanya kepada [Ibnu 'Abbas], maka dia menjelaskan; Ketika turun firman Allah yang serupa ini pada surah al Furqan, orang-orang musyrik penduduk Makkah berkata; \"Sungguh kita telah membunuh jiwa yang diharamkan Allah dan kita juga menyembah selain Allah dan kita telah banyak berbuat maksiat, maka Allah menurunkan firman-Nya yang artinya: \"...kecuali siapa yang bertaubat dan beriman...\" (QS al Furqan ayat 70). Nah, ayat-ayat ini turun untuk mereka. Adapun ayat yang ada dalam surah an Nisaa' adalah bila seseorang telah mengenal Islam dan syari'atnya, kemudian dia membunuh seseorang dengan sengaja maka balasan baginya adalah neraka jahannam\". Kemudian keterangan ini aku sampaikan kepada Mujahidmaka dia berkata; \"Kecuali siapa yang menyesali perbuartannya\"."},{"p":"Bukhari","n":4303,"ar":"حَدَّثَنَا سَعِيدُ بْنُ عُفَيْرٍ قَالَ حَدَّثَنِي اللَّيْثُ قَالَ حَدَّثَنِي عُقَيْلٌ عَنْ ابْنِ شِهَابٍ قَالَ حَدَّثَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخْرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ الْقَارِيَّ حَدَّثَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ لِقِرَاءَتِهِ فَإِذَا هُوَ يَقْرَأُ عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَتَصَبَّرْتُ حَتَّى سَلَّمَ فَلَبَّبْتُهُ بِرِدَائِهِ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَأُ قَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ كَذَبْتَ فَإِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قَدْ أَقْرَأَنِيهَا عَلَى غَيْرِ مَا قَرَأْتَ فَانْطَلَقْتُ بِهِ أَقُودُهُ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ بِسُورَةِ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ اقْرَأْ يَا هِشَامُ فَقَرَأَ عَلَيْهِ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَلِكَ أُنْزِلَتْ ثُمَّ قَالَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُ الْقِرَاءَةَ الَّتِي أَقْرَأَنِي فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ كَذَلِكَ أُنْزِلَتْ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","trj":"Telah menceritakan kepada kami [Sa'id bin Ufair] ia berkata, Telah menceritakan kepadaku [Al Laits] ia berkata; Telah menceritakan kepadaku [Uqail] dari [Ibnu Syihab] ia berkata; Telah menceritakan kepadaku [Urwah bin Zubair] bahwa [Al Miswar bin Makhzamah] dan [Abdurrahman bin Abd Al Qari`] keduanya menceritakan kepadanya bahwa keduanya mendengar [Umar bin Al Khaththab] berkata, \"Aku pernah mendengar Hisyam bin Hakim bin Hizam sedang membaca surat Al Furqan di masa Rasulullah shallallahu 'alaihi wasallam, aku pun mendengarkan bacaannya dengan seksama. Maka, ternyata ia membacakan dengan huruf yang banyak yang Rasulullah shallallahu 'alaihi wasallam belum pernah membacakannya seperti itu padaku. Maka aku hampir saja mencekiknya saat shalat, namun aku pun bersabar menunggu sampai ia selesai salam. Setelah itu, aku langsung meninting lengan bajunya seraya bertanya, \"Siapa yang membacakan surat ini yang telah aku dengan ini kepadamu?\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam yang telah membacakannya padaku.\" Aku katakan, \"Kamu telah berdusta. Sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah membacakannya padaku, namun tidak sebagaimana apa yang engkau baca.\" Maka aku pun segera menuntunnya untuk menemui Rasulullah shallallahu 'alaihi wasallam. Selanjutnya, kukatakan kepada beliau, \"Sesungguhnya aku mendengar orang ini membaca surat Al Furqan dengan huruf (dialek bacaan) yang belum pernah Anda bacakan kepadaku.\" Maka Rasulullah shallallahu 'alaihi wasallam pun bersabda: \"Bacalah wahai Hisyam.\" Lalu ia pun membaca dengan bacaan yang telah aku dengar sebelumnya. Kemudian Rasulullah shallallahu 'alaihi wasallam bersabda: \"Begitulah ia diturunkan.\" Kemudian beliau bersabda: \"Bacalah wahai Umar.\" Maka aku pun membaca dengan bacaan sebagaimana yang dibacakan oleh Rasulullah shallallahu 'alaihi wasallam kepadaku. Setelah itu, beliau bersabda: \"Seperti itulah surat itu diturunkan. Sesungguhnya Al Qur`an ini diturunkan dengan tujuh huruf (tujuh dialek bacaan). Maka bacalah ia, sesuai dengan dialek bacaan yang kalian bisa.\""},{"p":"Bukhari","n":4348,"ar":"حَدَّثَنَا أَبُو الْيَمَانِ أَخْبَرَنَا شُعَيْبٌ عَنْ الزُّهْرِيِّ قَالَ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ عَنْ حَدِيثِ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ لِقِرَاءَتِهِ فَإِذَا هُوَ يَقْرَؤُهَا عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَانْتَظَرْتُهُ حَتَّى سَلَّمَ فَلَبَبْتُهُ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَأُ قَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ لَهُ كَذَبْتَ فَوَاللَّهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُوَ أَقْرَأَنِي هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ فَانْطَلَقْتُ بِهِ إِلَى رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقُودُهُ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا وَإِنَّكَ أَقْرَأْتَنِي سُورَةَ الْفُرْقَانِ فَقَالَ يَا هِشَامُ اقْرَأْهَا فَقَرَأَهَا الْقِرَاءَةَ الَّتِي سَمِعْتُهُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُهَا الَّتِي أَقْرَأَنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","trj":"Telah menceritakan kepada kami [Abul Yaman] Telah mengabarkan kepada kami [Syu'aib] dari [Az Zuhri] ia berkata; Telah mengabarkan kepadaku [Urwah bin Zubair] dari hadits [Al Miswar bin Makhzamah] dan [Abdurrahman bin Abd Al Qari`] bahwa keduanya mendengar [Umar bin Al Khaththab] berkata, Pada masa Rasulullah shallallahu 'alaihi wasallam, aku pernah mendengar Hisyam bin Hakim bin Hizam membacakan surat Al Furqan, maka aku pun mendengarkan bacaannya dengan seksama. Dan ternyata ia membacanya dengan Huruf (cara bacaan) yang begitu banyak, yang Rasulullah shallallahu 'alaihi wasallam sendiri belum membacakan bacaan seperti itu padaku, maka aku pun ingin segera menyergapnya di dalam shalat, namun aku menunggunya hingga selesai salam dan langsung meninting lengan bajunya seraya bertanya, \"Siapa yang membacakan surat ini padamu?\" Ia menjawab, \"Rasulullah shallallahu 'alaihi wasallam yang membacakannya padaku.\" Maka kukatakan padanya, \"Kamu telah berdusta. Demi Allah, sesungguhnya Rasulullah shallallahu 'alaihi wasallam telah membacakan surat -yang telah aku dengar ini darimu- padaku.\" Maka aku pun segera membawanya menghadap Rasulullah shallallahu 'alaihi wasallam. Aku berkata, \"Wahai Rasulullah shallallahu 'alaihi wasallam, aku mendengar orang ini membaca surat Al Furqan dengan cara baca yang belum pernah Anda ajarkan padakku. Dan sungguh, Anda telah membacakan surat Al Furqan padaku.\" Akhirnya beliau bersabda: \"Wahai Hisyam, bacalah surat itu.\" Maka Hisyam pun membacanya bacaan yang telah aku dengan sebelumnya. Lalu Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seperti inilah surat itu diturunkan.\" Kemudian beliau bersabda lagi: \"Bacalah wahai Umar.\" Lalu aku pun membacanya sebagaimana yang telah diajarkan beliau. Kemudian beliau bersabda: \"Seperti ini pulalah ia diturunkan.\" Dan Rasulullah shallallahu 'alaihi wasallam bersabda lagi: \"Al Qur`an diturunkan dengan Sab'atu Ahruf (tujuh dialek) karena itu bacalah sesuai kemampuan kalian.\""},{"p":"Bukhari","n":5237,"ar":"حَدَّثَنَا مُحَمَّدُ بْنُ كَثِيرٍ أَخْبَرَنَا سُفْيَانُ عَنْ مَنْصُورٍ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ عَنْ عَبْدِ اللَّهِ قَالَقُلْتُ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَعْظَمُ قَالَ أَنْ تَجْعَلَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قُلْتُ ثُمَّ أَيُّ قَالَ أَنْ تَقْتُلَ وَلَدَكَ خَشْيَةَ أَنْ يَأْكُلَ مَعَكَ قَالَ ثُمَّ أَيُّ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ وَأَنْزَلَ اللَّهُ تَصْدِيقَ قَوْلِ النَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Muhammad bin Katsir] telah mengabarkan kepada kami [Sufyan] dari [Manshur] dari [Abu Wa`il] dari ['Amru bin Syurahbil] dari [Abdullah] dia berkata; saya bertanya; Wahai Rasulullah, dosa apakah yang paling besar? Beliau menjawab: \"Kamu menjadikan tandingan bagi Allah, padahal Dia adalah yang menciptakanmu.\" Kemudian apalagi?\" beliau bersabda: \"Kamu membunuh anakmu karena takut dia makan bersamamu.\" Dia berkata; \"Kemudian apalagi?\" beliau bersabda: \"Kamu mencinahi isteri tetanggamu sendiri.\" Dan Allah telah menurunkan kebenaran sabda Nabi-Nya shallallahu 'alaihi wasallam Dan orang-orang yang tidak menyeru Allah dengan tuhan-tuhan yang lain. QS Al Furqan; 68."},{"p":"Bukhari","n":6608,"ar":"حَدَّثَنَا قُتَيْبَةُ بْنُ سَعِيدٍ حَدَّثَنَا جَرِيرٌ عَنْ الْأَعْمَشِ عَنْ أَبِي وَائِلٍ عَنْ عَمْرِو بْنِ شُرَحْبِيلَ قَالَ قَالَ عَبْدُ اللَّهِقَالَ رَجُلٌ يَا رَسُولَ اللَّهِ أَيُّ الذَّنْبِ أَكْبَرُ عِنْدَ اللَّهِ قَالَ أَنْ تَدْعُوَ لِلَّهِ نِدًّا وَهُوَ خَلَقَكَ قَالَ ثُمَّ أَيْ قَالَ ثُمَّ أَنْ تَقْتُلَ وَلَدَكَ مَخَافَةَ أَنْ يَطْعَمَ مَعَكَ قَالَ ثُمَّ أَيْ قَالَ أَنْ تُزَانِيَ حَلِيلَةَ جَارِكَ فَأَنْزَلَ اللَّهُ تَصْدِيقَهَا{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا يُضَاعَفْ لَهُ الْعَذَابُ }الْآيَةَ","trj":"Telah menceritakan kepada kami [Qutaibah bin Sa'id] telah menceritakan kepada kami [Jarir] dari [Al A'masy] dari [Abu Wail] dari ['Amru bin Syurahbil] berkata, [Abdullah] berkata, \"Seorang laki-laki berkata, 'Wahai Rasulullah, dosa apakah yang terbesar di sisi Allah? ' Nabi menjawab: 'Engkau menjadikan tandingan bagi Allah, padahal Dialah yang menciptamu.' Laki-laki tersebut bertanya lagi, 'Lantas apa lagi? ' Nabi menjawab: 'Engkau bunuh anakmu karena khawatir makan bersamamu.' Laki-laki itu bertanya lagi, 'Lantas apa? ' Nabi menjawab: 'Engkau berzina dengan wanita tetanggamu.' Lantas Allah menurunkan ayat yang membenarkannya: '(Dan orang-orang yang tidak menyeru Tuhan lain disamping menyeru Allah, dan tidak membunuh jiwa yang Allah haramkan selain dengan alasan yang benar, dan tidak berzina, dan barangsiapa melakukan yang demikian ia akan memperoleh dosa dan akan dilipat gandakan siksa baginya) '. (Qs. Al Furqan: 68-69)."},{"p":"Malik","n":420,"ar":"حَدَّثَنِي يَحْيَى عَنْ مَالِك عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَنَّهُ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا فَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ ثُمَّ قَالَ اقْرَأْ يَا هِشَامُ فَقَرَأَ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِي اقْرَأْ فَقَرَأْتُهَا فَقَالَ هَكَذَا أُنْزِلَتْ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُ","trj":"Telah menceritakan kepadaku Yahya dari Malik dari [Ibnu Syihab] dari [Urwah bin Az Zubair] dari [Abdurrahman bin Abdu Al Qari] ia berkata; Aku mendengar [Umar bin Khatthab] berkata, \"Aku mendengar Hisyam bin Hakim bin Hizam membaca Surat Al Furqan dengan bacaan yang berbeda dengan yang biasanya aku baca, padahal Rasulullah shallallahu 'alaihi wasallam membacakan kepadaku. Maka hampir saja aku tergesa-gesa memarahinya, namun aku biarkan hingga dia selesai. Aku tarik surbannya dan aku bawa menemui Rasulullah shallallahu 'alaihi wasallam. Aku katakan kepada beliau, \"Wahai Rasulullah, aku mendengar orang ini membaca Surat Al Furqan tidak sebagaimana yang engkau bacakan untukku! \" Rasulullah shallallahu 'alaihi wasallam bersabda: \"Bawa dia kepadaku! \" Kemudian beliau bersabda: \"Bacalah, Wahai Hisyam.\" Hisyam membacanya sebagaimana yang aku dengar. Rasulullah shallallahu 'alaihi wasallam bersabda: \"Seperti inilah surat ini diturunkan, \" Kemudian beliau berkata padaku: \"Bacalah.\" Akupun membacanya, lalu beliau bersabda: \"Seperti ini juga surat ini diturunkan. Sesungguhnya Qur'an itu diturunkan dalam tujuh bahasa (cara membaca), bacalah apa yang mudah bagimu.\" "},{"p":"Muslim","n":173,"ar":"حَدَّثَنِي مُحَمَّدُ بْنُ حَاتِمِ بْنِ مَيْمُونٍ وَإِبْرَاهِيمُ بْنُ دِينَارٍ وَاللَّفْظُ لِإِبْرَاهِيمَ قَالَا حَدَّثَنَا حَجَّاجٌ وَهُوَ ابْنُ مُحَمَّدٍ عَنْ ابْنِ جُرَيْجٍ قَالَ أَخْبَرَنِي يَعْلَى بْنُ مُسْلِمٍ أَنَّهُ سَمِعَ سَعِيدَ بْنَ جُبَيْرٍ يُحَدِّثُ عَنْ ابْنِ عَبَّاسٍأَنَّ نَاسًا مِنْ أَهْلِ الشِّرْكِ قَتَلُوا فَأَكْثَرُوا وَزَنَوْا فَأَكْثَرُوا ثُمَّ أَتَوْا مُحَمَّدًا صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالُوا إِنَّ الَّذِي تَقُولُ وَتَدْعُو لَحَسَنٌ وَلَوْ تُخْبِرُنَا أَنَّ لِمَا عَمِلْنَا كَفَّارَةً فَنَزَلَ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ وَلَا يَزْنُونَ وَمَنْ يَفْعَلْ ذَلِكَ يَلْقَ أَثَامًا }وَنَزَلَ{ يَا عِبَادِيَ الَّذِينَ أَسْرَفُوا عَلَى أَنْفُسِهِمْ لَا تَقْنَطُوا مِنْ رَحْمَةِ اللَّهِ }","trj":"Telah menceritakan kepada kami [Muhammad bin Hatim bin Maimun] dan [Ibrahim bin Dinar] dan lafazh tersebut milik Ibrahim, keduanya berkata, telah menceritakan kepada kami [Hajjaj] -yaitu Ibnu Muhammad- dari [Ibnu Juraij] dia berkata, telah mengabarkan kepadaku [Ya'la bin Muslim] bahwa dia mendengar [Sa'id bin Jubair] menceritakan dari [Ibnu Abbas] bahwa orang-orang dari kaum musyrikin melakukan pembunuhan, dan hal itu semakin merajalela, dan mereka melakukan perzinahan, dan hal itupun semakin merajalela. Kemudian mereka mendatangi Nabi Muhammad shallallahu 'alaihi wasallam dan berkata, 'Sungguh sesuatu yang selalu engkau katakan dan engkau serukan adalah baik adanya, sekiranya engkau mengabarkan kepada kami bahwa amalan-amalan jelek yang telah kami perbuat dapat terhapus, maka turunlah ayat: '(Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar, dan tidak berzina, barang siapa yang melakukan yang demikian itu, niscaya dia mendapat (pembalasan) dosa(nya)) ' (Qs. Al Furqan: 68). Lalu turunlah ayat: '(Katakanlah, 'Hai hamba-hambaKu yang malampaui batas terhadap diri mereka sendiri, janganlah kamu berputus asa dari rahmat Allah) ' (Qs. Az Zumar: 53)."},{"p":"Muslim","n":1273,"ar":"حَدَّثَنَا يَحْيَى بْنُ يَحْيَى قَالَ قَرَأْتُ عَلَى مَالِكٍ عَنْ ابْنِ شِهَابٍ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ عَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ قَالَ سَمِعْتُ عُمَرَ بْنَ الْخَطَّابِ يَقُولُاسَمِعْتُ هِشَامَ بْنَ حَكِيمِ بْنِ حِزَامٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَؤُهَا وَكَانَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَقْرَأَنِيهَا فَكِدْتُ أَنْ أَعْجَلَ عَلَيْهِ ثُمَّ أَمْهَلْتُهُ حَتَّى انْصَرَفَ ثُمَّ لَبَّبْتُهُ بِرِدَائِهِ فَجِئْتُ بِهِ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى غَيْرِ مَا أَقْرَأْتَنِيهَا فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ اقْرَأْ فَقَرَأَ الْقِرَاءَةَ الَّتِي سَمِعْتُهُ يَقْرَأُ فَقَالَ رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِي اقْرَأْ فَقَرَأْتُ فَقَالَ هَكَذَا أُنْزِلَتْ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُو حَدَّثَنِي حَرْمَلَةُ بْنُ يَحْيَى أَخْبَرَنَا ابْنُ وَهْبٍ أَخْبَرَنِي يُونُسُ عَنْ ابْنِ شِهَابٍ أَخْبَرَنِي عُرْوَةُ بْنُ الزُّبَيْرِ أَنَّ الْمِسْوَرَ بْنَ مَخَرَمَةَ وَعَبْدَ الرَّحْمَنِ بْنَ عَبْدٍ الْقَارِيَّ أَخْبَرَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُا سَمِعْتُ هِشَامَ بْنَ حَكِيمٍ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ وَسَاقَ الْحَدِيثَ بِمِثْلِهِ وَزَادَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَتَصَبَّرْتُ حَتَّى سَلَّمَ حَدَّثَنَا إِسْحَقُ بْنُ إِبْرَاهِيمَ وَعَبْدُ بْنُ حُمَيْدٍ قَالَا أَخْبَرَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ كَرِوَايَةِ يُونُسَ بِإِسْنَادِهِ","trj":"Telah menceritakan kepada kami [Yahya bin Yahya] ia berkata, saya telah membacakan kepada [Malik] dari [Ibnu Syihab] dari [Urwah bin Zubair] dari [Abdurrahman bin Abdul Qari] ia berkata, saya mendengar [Umar bin Al Khaththab] berkata; Aku mendengar Hisyam bin Hakim bin Hizam membaca surat Al Furqan, tidak seperti bacaan (qiraat) yang pernah beliau shallallahu 'alaihi wasallam bacakan kepadaku. Karena itu hampir saja aku bertindak kasar terhadapnya. Tetapi kubiarkan saja dia hingga pergi. Namun kupegang bajunya, lalu kubawa dia ke hadapan Rasulullah shallallahu 'alaihi wasallam. Ujarku, \"Wahai Rasulullah, aku mendengar orang ini membaca surat Al Furqan tidak seperti yang Anda bacakan kepadaku, bagaimana ini?\" Rasulullah shallallahu 'alaihi wasallam menjawab: \"Lepaskanlah ia, suruh ia membacanya kembali.\" Lalu Hisyam membacakan kembali seperti yang dibacanya tadi. Setelah itu, Nabi shallallahu 'alaihi wasallam bersabda: \"Memang seperti inilah ia diturunkan.\" Kemudian Nabi shallallahu 'alaihi wasallam menyuruhku pula untuk membaca. Lalu kubaca seperti bacaan yang biasa kubaca. Maka Nabi shallallahu 'alaihi wasallam bersabda: \"Ya, ayat itu memang diturunkan seperti itu. Sesungguhnya Al Qur`an itu diturunkan dengan tujuh huruf (tujuh dialek bahasa). Karena itu, bacalah dengan huruf yang mudah bagi kalian.\" Dan telah menceritakan kepadaku [Harmalah bin Yahya] telah mengabarkan kepada kami [Ibnu Wahb] telah mengabarkan kepadaku [Yunus] dari [Ibnu Syihab] telah mengabarkan kepadaku [Urwah bin Zubair] bahwa [Miswar bin Makhramah] dan [Abdurrahman bin Abdul Qari] telah mengarbarkan kepadanya, bahwa keduanya telah mendengar [Umar bin Al Khaththab] berkata; Saya mendengar Hisyam bin Hakim membaca surat Al Furqan pada masa Rasulullah shallallahu 'alaihi wasallam. Ia pun menyebutkan hadits yang serupa. Dan ia menambahkan; \"Dan aku hampir saja berbuat kasar terhadapnya di saat shalat. Namun aku berusaha bersabar hingga ia mengucapkan salam.\" Telah menceritakan kepada kami [Ishaq bin Ibrahim] dan [Abd bin Humaid] keduanya berkata, telah mengabarkan kepada kami [Abdurrazaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] sebagaimana riwayat Yunus dengan Isnadnya."},{"p":"Nasa'i","n":4566,"ar":"أَخْبَرَنَا عَمْرُو بْنُ عَلِيٍّ قَالَ حَدَّثَنَا يَحْيَى قَالَ حَدَّثَنَا ابْنُ جُرَيْجٍ قَالَ أَخْبَرَنِي الْقَاسِمُ بْنُ أَبِي بَزَّةَ عَنْ سَعِيدِ بْنِ جُبَيْرٍ قَالَقُلْتُ لِابْنِ عَبَّاسٍ هَلْ لِمَنْ قَتَلَ مُؤْمِنًا مُتَعَمِّدًا مِنْ تَوْبَةٍ قَالَ لَا وَقَرَأْتُ عَلَيْهِ الْآيَةَ الَّتِي فِي الْفُرْقَانِ{ وَالَّذِينَ لَا يَدْعُونَ مَعَ اللَّهِ إِلَهًا آخَرَ وَلَا يَقْتُلُونَ النَّفْسَ الَّتِي حَرَّمَ اللَّهُ إِلَّا بِالْحَقِّ }قَالَ هَذِهِ آيَةٌ مَكِّيَّةٌ نَسَخَتْهَا آيَةٌ مَدَنِيَّةٌ{ وَمَنْ يَقْتُلْ مُؤْمِنًا مُتَعَمِّدًا فَجَزَاؤُهُ جَهَنَّمُ }","trj":"Telah mengabarkan kepada kami ['Amru bin Ali] telah menceritakan kepada kami [Yahya] telah menceritakan kepada kami [Ibnu Juraij] telah menceritakan kepadaku [Al Qasim bin Abu Bazzah] dari [Sa'id bin Jubair], dia berkata; \"Saya berkata kepada [Ibnu Abbas]; \"Apakah ada taubat bagi orang yang membunuh seorang mukmin secara sengaja?\" Dia berkata; \"Tidak.\" Dan saya membacakan kepadanya ayat yang ada dalam surat Al Furqan: Dan orang-orang yang tidak menyembah tuhan yang lain beserta Allah dan tidak membunuh jiwa yang diharamkan Allah (membunuhnya) kecuali dengan (alasan) yang benar. Dia berkata; \"Ini adalah ayat Makkiyah dan dihapus oleh ayat Madaniyah. Yaitu: Barang siapa yang membunuh seorang mukmin dengan sengaja maka balasannya adalah Neraka Jahannam"},{"p":"Tirmidzi","n":2798,"ar":"حَدَّثَنَا الْحَسَنُ بْنُ عَلِيٍّ الْخَلَّالُ وَغَيْرُ وَاحِدٍ قَالُوا حَدَّثَنَا عَبْدُ الرَّزَّاقِ أَخْبَرَنَا مَعْمَرٌ عَنْ الزُّهْرِيِّ عَنْ عُرْوَةَ بْنِ الزُّبَيْرِ عَنْ الْمِسْوَرِ بْنِ مَخْرَمَةَ وَعَبْدِ الرَّحْمَنِ بْنِ عَبْدٍ الْقَارِيِّ أَخْبَرَاهُ أَنَّهُمَا سَمِعَا عُمَرَ بْنَ الْخَطَّابِ يَقُولُمَرَرْتُ بِهِشَامِ بْنِ حَكِيمِ بْنِ حِزَامٍ وَهُوَ يَقْرَأُ سُورَةَ الْفُرْقَانِ فِي حَيَاةِ رَسُولِ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَاسْتَمَعْتُ قِرَاءَتَهُ فَإِذَا هُوَ يَقْرَأُ عَلَى حُرُوفٍ كَثِيرَةٍ لَمْ يُقْرِئْنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَكِدْتُ أُسَاوِرُهُ فِي الصَّلَاةِ فَنَظَرْتُ حَتَّى سَلَّمَ فَلَمَّا سَلَّمَ لَبَّبْتُهُ بِرِدَائِهِ فَقُلْتُ مَنْ أَقْرَأَكَ هَذِهِ السُّورَةَ الَّتِي سَمِعْتُكَ تَقْرَؤُهَا فَقَالَ أَقْرَأَنِيهَا رَسُولُ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ قُلْتُ لَهُ كَذَبْتَ وَاللَّهِ إِنَّ رَسُولَ اللَّهِ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ لَهُوَ أَقْرَأَنِي هَذِهِ السُّورَةَ الَّتِي تَقْرَؤُهَا فَانْطَلَقْتُ أَقُودُهُ إِلَى ا��نَّبِيِّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقُلْتُ يَا رَسُولَ اللَّهِ إِنِّي سَمِعْتُ هَذَا يَقْرَأُ سُورَةَ الْفُرْقَانِ عَلَى حُرُوفٍ لَمْ تُقْرِئْنِيهَا وَأَنْتَ أَقْرَأْتَنِي سُورَةَ الْفُرْقَانِ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ أَرْسِلْهُ يَا عُمَرُ اقْرَأْ يَا هِشَامُ فَقَرَأَ عَلَيْهِ الْقِرَاءَةَ الَّتِي سَمِعْتُ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ لِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ اقْرَأْ يَا عُمَرُ فَقَرَأْتُ بِالْقِرَاءَةِ الَّتِي أَقْرَأَنِي النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ فَقَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ هَكَذَا أُنْزِلَتْ ثُمَّ قَالَ النَّبِيُّ صَلَّى اللَّهُ عَلَيْهِ وَسَلَّمَ إِنَّ هَذَا الْقُرْآنَ أُنْزِلَ عَلَى سَبْعَةِ أَحْرُفٍ فَاقْرَءُوا مَا تَيَسَّرَ مِنْهُقَالَ أَبُو عِيسَى هَذَا حَدِيثٌ حَسَنٌ صَحِيحٌ وَقَدْ رَوَاهُ مَالِكُ بْنُ أَنَسٍ عَنْ الزُّهْرِيِّ بِهَذَا الْإِسْنَادِ نَحْوَهُ إِلَّا أَنَّهُ لَمْ يَذْكُرْ فِيهِ الْمِسْوَرَ بْنَ مَخْرَمَةَ","trj":"Telah menceritakan kepada kami [Al Hasan bin Ali Al Khallal] dan yang lain, mereka berkata; telah menceritakan kepada kami [Abdurrazzaq] telah mengabarkan kepada kami [Ma'mar] dari [Az Zuhri] dari ['Urwah bin Az Zubair] dari [Al Miswar bin Makhramah] dan [Abdurrahman bin Abd Al Qari`] keduanya mengebarkan bahwa keduanya mendengar [Umar bin Al Khaththab] berkata; \"Pada masas Rasulullah Shallallau 'alaihi wasallam masih hidup, aku melewati Hisyam bin Hakim bin Hizam, ketika itu ia tengah membaca surat Al Furqan, dan aku sempat mendengar bacaannya, ia membaca dalam beberapa bacaan yang tidak pernah dibacakan oleh Rasulullah shallallahu 'alaihi wasallam kepadaku, lantas aku hampir menarik kepalanya dalam shalat, aku terus saja melihatnya hingga ia salam, seusai salam aku tarik selendangnya, aku bertanya; \"Tadi aku sempat mendengarmu membaca surat (Al Qur'an), siapa yang membacakan surat (Al Qur'an) tersebut padamu?\" Ia menjawab; Rasulullah shallallahu 'alaihi wasallam-lah yang membacakannya padaku.\" Aku berkata padanya; \"Bohong. Demi Allah, Rasulullah shallallahu 'alaihi wasallam juga pernah membacakan surat yang kau baca itu padaku.\" Aku beranjak seraya menuntunnya menuju Nabi shallallahu 'alaihi wasallam, aku berkata; \"Wahai Rasulullah, aku tadi mendengar dia membaca surat Al Furqan dengan beberapa bacaan yang tidak anda bacakan padaku, sementara anda telah membacakan surat Al Furqan padaku.\" Nabi shallallahu 'alaihi wasallam bersabda: \"Lepaskan dia wahai Umar, dan bacalah hai Hisyam.\" Hisyam pun membaca bacaan yang aku dengar, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Seperti itulah (surat Al Furqan) diturunkan.\" Kemudian Nabi shallallahu 'alaihi wasallam bersabda kepadaku: \"Bacalah, hai Umar, \" aku pun membaca dengan bacaan yang Nabi shallallahu 'alaihi wasallam bacakan padaku, lalu Nabi shallallahu 'alaihi wasallam bersabda: \"Seperti itulah (surat Al Furqan) diturunkan.\" Setelah itu Nabi shallallahu 'alaihi wasallam bersabda: \"Sesungguhnya al-Qur'an ini diturunkan dalam tujuh huruf, maka bacalah yang mudah darinya.\" Abu Isa berkata; Hadits ini hasan shahih. [Malik bin Anas] dari [Az Zurhi] dengan sanad dan maksud yang sama, hanya saja ia tidak menyebut: \"Al Miswar bin Al Makhramah.\""}]};
